export interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_RANGES: Record<keyof CronResult, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function parseSegment(segment: string, min: number, max: number): number[] {
  const values = new Set<number>();

  if (segment.includes("/")) {
    const [rangeExpr, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Invalid step value: "${segment}"`);
    }

    let start = min;
    let end = max;

    if (rangeExpr !== "*") {
      if (rangeExpr.includes("-")) {
        const [s, e] = rangeExpr.split("-").map(Number);
        start = s;
        end = e;
      } else {
        start = parseInt(rangeExpr, 10);
        end = max;
      }
    }

    if (isNaN(start) || isNaN(end)) {
      throw new RangeError(`Invalid range in step expression: "${segment}"`);
    }
    if (start < min || end > max || start > end) {
      throw new RangeError(`Range out of bounds [${min}-${max}]: "${segment}"`);
    }

    for (let i = start; i <= end; i += step) {
      values.add(i);
    }
  } else if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new RangeError(`Invalid range: "${segment}"`);
    }
    if (start > end) {
      throw new RangeError(`Range start must not exceed end: "${segment}"`);
    }
    if (start < min || end > max) {
      throw new RangeError(`Range out of bounds [${min}-${max}]: "${segment}"`);
    }

    for (let i = start; i <= end; i++) {
      values.add(i);
    }
  } else if (segment === "*") {
    for (let i = min; i <= max; i++) {
      values.add(i);
    }
  } else {
    const num = parseInt(segment, 10);

    if (isNaN(num) || String(num) !== segment.trim()) {
      throw new TypeError(`Invalid value: "${segment}"`);
    }
    if (num < min || num > max) {
      throw new RangeError(`Value ${num} out of bounds [${min}-${max}]`);
    }

    values.add(num);
  }

  return Array.from(values).sort((a, b) => a - b);
}

function parseField(expr: string, min: number, max: number): number[] {
  const segments = expr.split(",");

  if (segments.length === 0 || segments.some((s) => s.trim() === "")) {
    throw new SyntaxError(`Empty or invalid field expression: "${expr}"`);
  }

  const allValues = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    for (const v of parseSegment(trimmed, min, max)) {
      allValues.add(v);
    }
  }

  return Array.from(allValues).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute:     parseField(minuteExpr,     FIELD_RANGES.minute.min,     FIELD_RANGES.minute.max),
    hour:       parseField(hourExpr,        FIELD_RANGES.hour.min,       FIELD_RANGES.hour.max),
    dayOfMonth: parseField(dayOfMonthExpr,  FIELD_RANGES.dayOfMonth.min, FIELD_RANGES.dayOfMonth.max),
    month:      parseField(monthExpr,       FIELD_RANGES.month.min,      FIELD_RANGES.month.max),
    dayOfWeek:  parseField(dayOfWeekExpr,   FIELD_RANGES.dayOfWeek.min,  FIELD_RANGES.dayOfWeek.max),
  };
}

export default parseCron;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronResult;

const FIELD_RANGES: Record<FieldName, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseSegment(expr: string, min: number, max: number): number[] {
  // Step value: */n or start/n or start-end/n
  if (expr.includes("/")) {
    const slashIdx = expr.indexOf("/");
    const rangeExpr = expr.slice(0, slashIdx);
    const stepStr = expr.slice(slashIdx + 1);
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value "${stepStr}" in expression "${expr}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangeExpr === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangeExpr.includes("-")) {
      [rangeMin, rangeMax] = parseRangeBounds(rangeExpr, expr);
    } else {
      rangeMin = parseInt(rangeExpr, 10);
      if (isNaN(rangeMin)) {
        throw new Error(`Invalid range start "${rangeExpr}" in expression "${expr}"`);
      }
      rangeMax = max;
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (expr === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [rangeMin, rangeMax] = parseRangeBounds(expr, expr);
    if (rangeMin > rangeMax) {
      throw new Error(`Range start ${rangeMin} exceeds end ${rangeMax} in expression "${expr}"`);
    }
    return Array.from({ length: rangeMax - rangeMin + 1 }, (_, i) => i + rangeMin);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value "${expr}": not a number`);
  }
  return [value];
}

function parseRangeBounds(rangeExpr: string, context: string): [number, number] {
  const parts = rangeExpr.split("-");
  if (parts.length !== 2) {
    throw new Error(`Invalid range "${rangeExpr}" in expression "${context}"`);
  }
  const start = parseInt(parts[0], 10);
  const end = parseInt(parts[1], 10);
  if (isNaN(start) || isNaN(end)) {
    throw new Error(`Non-numeric bounds in range "${rangeExpr}" in expression "${context}"`);
  }
  return [start, end];
}

function parseField(expr: string, min: number, max: number, fieldName: FieldName): number[] {
  // Comma-separated list — each element is parsed independently
  const parts = expr.split(",");
  const raw = parts.length > 1
    ? parts.flatMap((part) => parseSegment(part.trim(), min, max))
    : parseSegment(expr.trim(), min, max);

  // Deduplicate and sort
  const unique = [...new Set(raw)].sort((a, b) => a - b);

  // Validate all values are within the allowed range
  for (const v of unique) {
    if (v < min || v > max) {
      throw new Error(
        `Value ${v} is out of range [${min}, ${max}] for field "${fieldName}"`
      );
    }
  }

  return unique;
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const fieldNames: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  const result = {} as CronResult;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(fields[i], min, max, name);
  }

  return result;
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(expression: string, min: number, max: number): number[] {
  const results = new Set<number>();

  const parts = expression.split(",");

  for (const part of parts) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) results.add(i);
      continue;
    }

    const stepMatch = trimmed.match(/^(\*|(\d+)-(\d+))\/(\d+)$/);
    if (stepMatch) {
      const step = parseInt(stepMatch[4], 10);
      if (step <= 0) throw new Error(`Invalid step value: ${step}`);

      let rangeMin = min;
      let rangeMax = max;

      if (stepMatch[1] !== "*") {
        rangeMin = parseInt(stepMatch[2], 10);
        rangeMax = parseInt(stepMatch[3], 10);
        validateRange(rangeMin, rangeMax, min, max);
      }

      for (let i = rangeMin; i <= rangeMax; i += step) results.add(i);
      continue;
    }

    const rangeMatch = trimmed.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) {
      const start = parseInt(rangeMatch[1], 10);
      const end = parseInt(rangeMatch[2], 10);
      validateRange(start, end, min, max);
      for (let i = start; i <= end; i++) results.add(i);
      continue;
    }

    const numMatch = trimmed.match(/^(\d+)$/);
    if (numMatch) {
      const value = parseInt(numMatch[1], 10);
      if (value < min || value > max) {
        throw new Error(`Value ${value} out of range [${min}, ${max}]`);
      }
      results.add(value);
      continue;
    }

    throw new Error(`Invalid cron field expression: "${trimmed}"`);
  }

  return Array.from(results).sort((a, b) => a - b);
}

function validateRange(start: number, end: number, min: number, max: number): void {
  if (start > end) throw new Error(`Invalid range: ${start}-${end} (start > end)`);
  if (start < min) throw new Error(`Value ${start} out of range [${min}, ${max}]`);
  if (end > max) throw new Error(`Value ${end} out of range [${min}, ${max}]`);
}

function parseCron(expression: string): CronResult {
  if (!expression || typeof expression !== "string") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  const result = {} as CronResult;

  for (let i = 0; i < fieldNames.length; i++) {
    const fieldName = fieldNames[i];
    const [min, max] = FIELD_RANGES[fieldName];
    result[fieldName] = parseField(fields[i], min, max);
  }

  return result;
}

export default parseCron;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = Object.assign({}, target);

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function generateRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const part of field.split(",")) {
    if (part === "*") {
      generateRange(min, max).forEach((v) => values.add(v));
    } else if (part.startsWith("*/")) {
      const step = parseInt(part.slice(2), 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${part}`);
      for (let i = min; i <= max; i += step) values.add(i);
    } else if (part.includes("/")) {
      const [rangePart, stepPart] = part.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${part}`);
      let rangeStart = min;
      let rangeEnd = max;
      if (rangePart !== "*") {
        if (rangePart.includes("-")) {
          const [s, e] = rangePart.split("-").map(Number);
          rangeStart = s;
          rangeEnd = e;
        } else {
          rangeStart = parseInt(rangePart, 10);
        }
      }
      validateRange(rangeStart, rangeEnd, min, max);
      for (let i = rangeStart; i <= rangeEnd; i += step) values.add(i);
    } else if (part.includes("-")) {
      const [start, end] = part.split("-").map(Number);
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${part}`);
      validateRange(start, end, min, max);
      generateRange(start, end).forEach((v) => values.add(v));
    } else {
      const num = parseInt(part, 10);
      if (isNaN(num)) throw new Error(`Invalid value: ${part}`);
      if (num < min || num > max) throw new Error(`Value ${num} out of range [${min}, ${max}]`);
      values.add(num);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

function validateRange(start: number, end: number, min: number, max: number): void {
  if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${start}-${end}`);
  if (start > end) throw new Error(`Range start ${start} exceeds end ${end}`);
  if (start < min || end > max) throw new Error(`Range [${start}, ${end}] out of bounds [${min}, ${max}]`);
}

function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField] = fields;
  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const fieldValues = [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField];

  const result = {} as CronResult;
  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(fieldValues[i], min, max);
  }

  return result;
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | unknown[];
    }
  }

  return result;
}

export default flattenObject;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 7 },   // dayOfWeek (0 and 7 both = Sunday)
];

function parseNumber(value: string): number {
  const num = parseInt(value, 10);
  if (isNaN(num) || String(num) !== value.trim()) {
    throw new Error(`Invalid number: "${value}"`);
  }
  return num;
}

function validateRange(value: number, min: number, max: number): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} is out of range [${min}, ${max}]`);
  }
}

function expandField(field: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Comma-separated list
  if (field.includes(",")) {
    const parts = field.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      const expanded = expandField(part.trim(), config);
      for (const v of expanded) values.add(v);
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  // Step value (e.g., "*/15" or "1-30/5")
  if (field.includes("/")) {
    const [rangePart, stepPart] = field.split("/");
    const step = parseNumber(stepPart);
    if (step <= 0) {
      throw new Error(`Step value must be positive: ${step}`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        rangeMin = parseNumber(startStr);
        rangeMax = parseNumber(endStr);
        validateRange(rangeMin, min, max);
        validateRange(rangeMax, min, max);
        if (rangeMin > rangeMax) {
          throw new Error(`Range start ${rangeMin} is greater than end ${rangeMax}`);
        }
      } else {
        rangeMin = parseNumber(rangePart);
        validateRange(rangeMin, min, max);
        rangeMax = max;
      }
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range (e.g., "1-5")
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseNumber(startStr);
    const end = parseNumber(endStr);
    validateRange(start, min, max);
    validateRange(end, min, max);
    if (start > end) {
      throw new Error(`Range start ${start} is greater than end ${end}`);
    }
    const values: number[] = [];
    for (let i = start; i <= end; i++) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (field === "*") {
    const values: number[] = [];
    for (let i = min; i <= max; i++) {
      values.push(i);
    }
    return values;
  }

  // Single number
  const num = parseNumber(field);
  validateRange(num, min, max);
  return [num];
}

function normalizeDayOfWeek(values: number[]): number[] {
  // Normalize 7 (Sunday) to 0
  const normalized = new Set(values.map(v => v === 7 ? 0 : v));
  return Array.from(normalized).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronResult {
  if (!expression || typeof expression !== "string") {
    throw new Error("Expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField] = fields;

  const minute = expandField(minuteField, FIELD_CONFIGS[0]);
  const hour = expandField(hourField, FIELD_CONFIGS[1]);
  const dayOfMonth = expandField(dayOfMonthField, FIELD_CONFIGS[2]);
  const month = expandField(monthField, FIELD_CONFIGS[3]);
  const dayOfWeekRaw = expandField(dayOfWeekField, FIELD_CONFIGS[4]);
  const dayOfWeek = normalizeDayOfWeek(dayOfWeekRaw);

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) {
      result[prefix] = obj as Primitive | Array<unknown>;
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) {
      result[prefix] = obj as unknown as Primitive;
    }
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronExpression, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Comma-separated list
  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) => parseField(part.trim(), config));
    const unique = [...new Set(values)].sort((a, b) => a - b);
    return unique;
  }

  // Wildcard
  if (field === "*") {
    return range(min, max);
  }

  // Step value: */n or start-end/n
  if (field.includes("/")) {
    const [rangePart, stepPart] = field.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${stepPart}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map((v) => parseInt(v, 10));
      if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range in step: "${rangePart}"`);
      start = s;
      end = e;
    } else {
      start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new Error(`Invalid start value in step: "${rangePart}"`);
      end = max;
    }

    if (start < min || start > max) throw new Error(`Value ${start} out of range [${min}, ${max}]`);
    if (end < min || end > max) throw new Error(`Value ${end} out of range [${min}, ${max}]`);
    if (start > end) throw new Error(`Range start ${start} exceeds end ${end}`);

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: start-end
  if (field.includes("-")) {
    const parts = field.split("-");
    if (parts.length !== 2) throw new Error(`Invalid range: "${field}"`);
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);

    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range values: "${field}"`);
    if (start < min || start > max) throw new Error(`Value ${start} out of range [${min}, ${max}]`);
    if (end < min || end > max) throw new Error(`Value ${end} out of range [${min}, ${max}]`);
    if (start > end) throw new Error(`Range start ${start} exceeds end ${end}`);

    return range(start, end);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) throw new Error(`Invalid value: "${field}"`);
  if (value < min || value > max) throw new Error(`Value ${value} out of range [${min}, ${max}]`);
  return [value];
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = parts;
  const fieldNames = Object.keys(FIELD_CONFIGS) as (keyof CronExpression)[];
  const fieldStrings = [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr];

  const result = {} as CronExpression;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    try {
      result[name] = parseField(fieldStrings[i], FIELD_CONFIGS[name]);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid "${name}" field ("${fieldStrings[i]}"): ${message}`);
    }
  }

  return result;
}

type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: unknown };

function flattenObject(obj: NestedObject, prefix = ""): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    return prefix ? { [prefix]: obj } : {};
  }

  const result: FlatObject = {};

  for (const [key, value] of Object.entries(obj)) {
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      const nested = flattenObject(value as NestedObject, flatKey);
      Object.assign(result, nested);
    } else {
      result[flatKey] = value;
    }
  }

  return result;
}

