export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const satisfies Record<keyof CronExpression, { min: number; max: number }>;

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}] in "${context}"`);
  }
}

function parseSinglePart(part: string, min: number, max: number): number[] {
  const values = new Set<number>();

  if (part === "*") {
    for (let i = min; i <= max; i++) values.add(i);
    return Array.from(values);
  }

  const slashIndex = part.indexOf("/");
  if (slashIndex !== -1) {
    const rangePart = part.slice(0, slashIndex);
    const stepStr  = part.slice(slashIndex + 1);
    const step = parseInt(stepStr, 10);

    if (!Number.isInteger(step) || step <= 0) {
      throw new TypeError(`Invalid step value "${stepStr}" in "${part}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes("-")) {
      const dashIndex = rangePart.indexOf("-");
      rangeMin = parseInt(rangePart.slice(0, dashIndex), 10);
      rangeMax = parseInt(rangePart.slice(dashIndex + 1), 10);
      if (!Number.isInteger(rangeMin) || !Number.isInteger(rangeMax)) {
        throw new TypeError(`Invalid range "${rangePart}" in "${part}"`);
      }
      assertInRange(rangeMin, min, max, part);
      assertInRange(rangeMax, min, max, part);
      if (rangeMin > rangeMax) {
        throw new RangeError(`Range start exceeds end in "${part}"`);
      }
    } else {
      rangeMin = parseInt(rangePart, 10);
      if (!Number.isInteger(rangeMin)) {
        throw new TypeError(`Invalid range start "${rangePart}" in "${part}"`);
      }
      assertInRange(rangeMin, min, max, part);
      rangeMax = max;
    }

    for (let i = rangeMin; i <= rangeMax; i += step) values.add(i);
    return Array.from(values);
  }

  const dashIndex = part.indexOf("-");
  if (dashIndex !== -1) {
    const start = parseInt(part.slice(0, dashIndex), 10);
    const end   = parseInt(part.slice(dashIndex + 1), 10);

    if (!Number.isInteger(start) || !Number.isInteger(end)) {
      throw new TypeError(`Invalid range "${part}"`);
    }
    assertInRange(start, min, max, part);
    assertInRange(end,   min, max, part);
    if (start > end) {
      throw new RangeError(`Range start exceeds end in "${part}"`);
    }

    for (let i = start; i <= end; i++) values.add(i);
    return Array.from(values);
  }

  const num = parseInt(part, 10);
  if (!Number.isInteger(num) || String(num) !== part.trim()) {
    throw new TypeError(`Invalid value "${part}"`);
  }
  assertInRange(num, min, max, part);
  values.add(num);

  return Array.from(values);
}

function parseField(field: string, min: number, max: number): number[] {
  if (!field || typeof field !== "string") {
    throw new TypeError(`Invalid field value: ${JSON.stringify(field)}`);
  }

  const parts = field.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new TypeError(`Empty segment in field "${field}"`);
    }
    for (const v of parseSinglePart(trimmed, min, max)) {
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (!expression || typeof expression !== "string") {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = fields;

  return {
    minute:     parseField(minuteStr,     FIELD_RANGES.minute.min,     FIELD_RANGES.minute.max),
    hour:       parseField(hourStr,       FIELD_RANGES.hour.min,       FIELD_RANGES.hour.max),
    dayOfMonth: parseField(dayOfMonthStr, FIELD_RANGES.dayOfMonth.min, FIELD_RANGES.dayOfMonth.max),
    month:      parseField(monthStr,      FIELD_RANGES.month.min,      FIELD_RANGES.month.max),
    dayOfWeek:  parseField(dayOfWeekStr,  FIELD_RANGES.dayOfWeek.min,  FIELD_RANGES.dayOfWeek.max),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | unknown[];
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  seen = new WeakSet<object>()
): FlatObject {
  if (obj === null || typeof obj !== "object") {
    return prefix ? { [prefix]: obj as Primitive } : {};
  }

  if (seen.has(obj)) {
    return prefix ? { [prefix]: "[Circular]" } : {};
  }

  seen.add(obj);

  const result: FlatObject = {};

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      const nested = flattenObject(value as NestedObject, flatKey, seen);
      Object.assign(result, nested);
    } else {
      result[flatKey] = value as Primitive | unknown[];
    }
  }

  seen.delete(obj);

  return result;
}

export default flattenObject;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function expandWildcard(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function expandStep(expr: string, min: number, max: number, fieldName: string): number[] {
  const [basePart, stepPart] = expr.split("/");
  const step = parseInt(stepPart, 10);

  if (isNaN(step) || step <= 0) {
    throw new RangeError(`Invalid step value "${stepPart}" in field "${fieldName}"`);
  }

  let start: number;
  let end: number;

  if (basePart === "*") {
    start = min;
    end = max;
  } else if (basePart.includes("-")) {
    const [rangeStart, rangeEnd] = basePart.split("-").map((v) => parseInt(v, 10));
    assertInRange(rangeStart, min, max, fieldName);
    assertInRange(rangeEnd, min, max, fieldName);
    if (rangeStart > rangeEnd) {
      throw new RangeError(`Range start ${rangeStart} > end ${rangeEnd} in field "${fieldName}"`);
    }
    start = rangeStart;
    end = rangeEnd;
  } else {
    start = parseInt(basePart, 10);
    assertInRange(start, min, max, fieldName);
    end = max;
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function expandRange(expr: string, min: number, max: number, fieldName: string): number[] {
  const [startStr, endStr] = expr.split("-");
  const start = parseInt(startStr, 10);
  const end = parseInt(endStr, 10);

  assertInRange(start, min, max, fieldName);
  assertInRange(end, min, max, fieldName);

  if (start > end) {
    throw new RangeError(`Range start ${start} > end ${end} in field "${fieldName}"`);
  }

  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseField(expr: string, fieldName: keyof CronFields): number[] {
  const { min, max } = FIELD_RANGES[fieldName];

  if (expr === "*") {
    return expandWildcard(min, max);
  }

  const parts = expr.split(",");
  const seen = new Set<number>();
  const values: number[] = [];

  for (const part of parts) {
    const trimmed = part.trim();

    if (trimmed === "") {
      throw new SyntaxError(`Empty token in field "${fieldName}"`);
    }

    let expanded: number[];

    if (trimmed.includes("/")) {
      expanded = expandStep(trimmed, min, max, fieldName);
    } else if (trimmed.includes("-")) {
      expanded = expandRange(trimmed, min, max, fieldName);
    } else {
      const num = parseInt(trimmed, 10);
      if (isNaN(num) || trimmed !== String(num)) {
        throw new SyntaxError(`Invalid token "${trimmed}" in field "${fieldName}"`);
      }
      assertInRange(num, min, max, fieldName);
      expanded = [num];
    }

    for (const v of expanded) {
      if (!seen.has(v)) {
        seen.add(v);
        values.push(v);
      }
    }
  }

  return values.sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but got ${fields.length}. Format: "minute hour dayOfMonth month dayOfWeek"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, "minute"),
    hour:       parseField(hourExpr,   "hour"),
    dayOfMonth: parseField(domExpr,    "dayOfMonth"),
    month:      parseField(monthExpr,  "month"),
    dayOfWeek:  parseField(dowExpr,    "dayOfWeek"),
  };
}

type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: unknown };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value;
    }
  }

  return result;
}

export default flattenObject;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 7 },   // dayOfWeek (0 and 7 both = Sunday)
];

function parseNumber(value: string): number {
  const num = parseInt(value, 10);
  if (isNaN(num) || value.trim() !== String(num)) {
    throw new Error(`Invalid number: "${value}"`);
  }
  return num;
}

function validateRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}-${max}] for ${context}`);
  }
}

function expandRange(min: number, max: number): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i++) {
    result.push(i);
  }
  return result;
}

function parseField(field: string, config: FieldConfig, fieldName: string): number[] {
  const { min, max } = config;

  // Wildcard
  if (field === "*") {
    return expandRange(min, max);
  }

  // Step value: */step or range/step
  if (field.includes("/")) {
    const [rangePart, stepPart] = field.split("/");
    if (!stepPart || stepPart === "") {
      throw new Error(`Invalid step expression: "${field}" for ${fieldName}`);
    }

    const step = parseNumber(stepPart);
    if (step <= 0) {
      throw new Error(`Step value must be positive, got ${step} for ${fieldName}`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      rangeMin = parseNumber(startStr);
      rangeMax = parseNumber(endStr);
      validateRange(rangeMin, min, max, fieldName);
      validateRange(rangeMax, min, max, fieldName);
      if (rangeMin > rangeMax) {
        throw new Error(`Range start ${rangeMin} > end ${rangeMax} for ${fieldName}`);
      }
    } else {
      rangeMin = parseNumber(rangePart);
      validateRange(rangeMin, min, max, fieldName);
      rangeMax = max;
    }

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      result.push(i);
    }
    return result;
  }

  // Comma-separated list
  if (field.includes(",")) {
    const parts = field.split(",");
    const values = new Set<number>();

    for (const part of parts) {
      const expanded = parseField(part.trim(), config, fieldName);
      for (const v of expanded) {
        values.add(v);
      }
    }

    return Array.from(values).sort((a, b) => a - b);
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseNumber(startStr);
    const end = parseNumber(endStr);
    validateRange(start, min, max, fieldName);
    validateRange(end, min, max, fieldName);
    if (start > end) {
      throw new Error(`Range start ${start} > end ${end} for ${fieldName}`);
    }
    return expandRange(start, end);
  }

  // Single number
  const num = parseNumber(field);
  validateRange(num, min, max, fieldName);
  return [num];
}

function normalizeDayOfWeek(values: number[]): number[] {
  // Normalize 7 (Sunday) to 0
  const normalized = new Set(values.map(v => (v === 7 ? 0 : v)));
  return Array.from(normalized).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronResult {
  if (!expression || typeof expression !== "string") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const fieldNames = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

  const [minuteField, hourField, domField, monthField, dowField] = fields;

  const minute = parseField(minuteField, FIELD_CONFIGS[0], "minute");
  const hour = parseField(hourField, FIELD_CONFIGS[1], "hour");
  const dayOfMonth = parseField(domField, FIELD_CONFIGS[2], "dayOfMonth");
  const month = parseField(monthField, FIELD_CONFIGS[3], "month");
  const dayOfWeekRaw = parseField(dowField, FIELD_CONFIGS[4], "dayOfWeek");
  const dayOfWeek = normalizeDayOfWeek(dayOfWeekRaw);

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export default parseCron;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
  name: string;
}

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59, name: "minute" },
  { min: 0, max: 23, name: "hour" },
  { min: 1, max: 31, name: "dayOfMonth" },
  { min: 1, max: 12, name: "month" },
  { min: 0, max: 7, name: "dayOfWeek" },
];

function assertInRange(value: number, config: FieldConfig): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `${config.name}: value ${value} is out of valid range [${config.min}-${config.max}]`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new TypeError(`Invalid numeric token "${raw}" in "${context}"`);
  }
  return parseInt(raw, 10);
}

function expandRange(start: number, end: number, step: number, config: FieldConfig): number[] {
  if (start > end) {
    throw new RangeError(
      `${config.name}: range start ${start} exceeds end ${end}`
    );
  }
  if (step < 1) {
    throw new RangeError(`${config.name}: step must be >= 1, got ${step}`);
  }
  assertInRange(start, config);
  assertInRange(end, config);
  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(v);
  }
  return values;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  // Step expression: base/step — base can be "*" or "N" or "N-M"
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const basePart = segment.slice(0, slashIdx);
    const stepPart = segment.slice(slashIdx + 1);
    const step = parseInteger(stepPart, segment);

    if (basePart === "*") {
      return expandRange(config.min, config.max, step, config);
    }
    if (basePart.includes("-")) {
      const dashIdx = basePart.indexOf("-");
      const start = parseInteger(basePart.slice(0, dashIdx), segment);
      const end = parseInteger(basePart.slice(dashIdx + 1), segment);
      return expandRange(start, end, step, config);
    }
    // Single number as base: N/step means start at N, step through max
    const start = parseInteger(basePart, segment);
    return expandRange(start, config.max, step, config);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(config.min, config.max, 1, config);
  }

  // Range: N-M
  if (segment.includes("-")) {
    const dashIdx = segment.indexOf("-");
    const start = parseInteger(segment.slice(0, dashIdx), segment);
    const end = parseInteger(segment.slice(dashIdx + 1), segment);
    return expandRange(start, end, 1, config);
  }

  // Single value
  const value = parseInteger(segment, segment);
  assertInRange(value, config);
  return [value];
}

function parseField(field: string, config: FieldConfig): number[] {
  if (!field || field.trim() === "") {
    throw new TypeError(`${config.name}: field must not be empty`);
  }

  // Comma-separated list — each segment parsed independently then merged
  const segments = field.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new TypeError(`${config.name}: empty segment in comma list "${field}"`);
    }
    for (const v of parseSegment(trimmed, config)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new TypeError("parseCron: expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `parseCron: expected 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}`
    );
  }

  const [minuteRaw, hourRaw, dayOfMonthRaw, monthRaw, dayOfWeekRaw] = fields;

  return {
    minute: parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour: parseField(hourRaw, FIELD_CONFIGS[1]),
    dayOfMonth: parseField(dayOfMonthRaw, FIELD_CONFIGS[2]),
    month: parseField(monthRaw, FIELD_CONFIGS[3]),
    dayOfWeek: parseField(dayOfWeekRaw, FIELD_CONFIGS[4]),
  };
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronExpression, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function buildRange(start: number, end: number): number[] {
  if (start > end) throw new Error(`Range start ${start} exceeds end ${end}`);
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function assertInBounds(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new Error(
      `Value ${value} out of valid range [${config.min}, ${config.max}] in "${context}"`
    );
  }
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Step expression: */n or start-end/n or start/n
  if (segment.includes("/")) {
    const slashIndex = segment.indexOf("/");
    const left = segment.slice(0, slashIndex);
    const right = segment.slice(slashIndex + 1);
    const step = parseInt(right, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value "${right}" in "${segment}"`);
    }

    let start: number;
    let end: number;

    if (left === "*") {
      start = min;
      end = max;
    } else if (left.includes("-")) {
      const [s, e] = left.split("-").map(n => parseInt(n, 10));
      if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range "${left}" in "${segment}"`);
      assertInBounds(s, config, segment);
      assertInBounds(e, config, segment);
      start = s;
      end = e;
    } else {
      const s = parseInt(left, 10);
      if (isNaN(s)) throw new Error(`Invalid step base "${left}" in "${segment}"`);
      assertInBounds(s, config, segment);
      start = s;
      end = max;
    }

    if (start > end) throw new Error(`Range start ${start} exceeds end ${end} in "${segment}"`);

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return buildRange(min, max);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const dashIndex = segment.indexOf("-");
    const s = parseInt(segment.slice(0, dashIndex), 10);
    const e = parseInt(segment.slice(dashIndex + 1), 10);
    if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range "${segment}"`);
    assertInBounds(s, config, segment);
    assertInBounds(e, config, segment);
    return buildRange(s, e);
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) throw new Error(`Invalid value "${segment}"`);
  assertInBounds(num, config, segment);
  return [num];
}

function parseField(field: string, config: FieldConfig): number[] {
  if (!field || field.trim() === "") {
    throw new Error("Empty cron field");
  }

  // Comma-separated list
  if (field.includes(",")) {
    const seen = new Set<number>();
    for (const part of field.split(",")) {
      const trimmed = part.trim();
      if (!trimmed) throw new Error(`Empty segment in comma list "${field}"`);
      for (const v of parseSegment(trimmed, config)) seen.add(v);
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSegment(field.trim(), config);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
