interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  // Comma-separated list
  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (field === "*") {
    return range(min, max);
  }

  // Step value: */step or start-end/step
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    let rangeStart = min;
    let rangeEnd = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        rangeStart = parseInt(startStr, 10);
        rangeEnd = parseInt(endStr, 10);
      } else {
        rangeStart = parseInt(rangePart, 10);
      }
    }

    if (isNaN(rangeStart) || isNaN(rangeEnd)) {
      throw new Error(`Invalid range in step expression: ${field}`);
    }

    validateRange(rangeStart, rangeEnd, min, max, field);

    const result: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) {
      result.push(i);
    }
    return result;
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: ${field}`);
    }

    validateRange(start, end, min, max, field);

    if (start > end) {
      throw new Error(`Range start ${start} is greater than end ${end} in: ${field}`);
    }

    return range(start, end);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid field value: ${field}`);
  }

  if (value < min || value > max) {
    throw new Error(`Value ${value} is out of range [${min}, ${max}] in: ${field}`);
  }

  return [value];
}

function validateRange(start: number, end: number, min: number, max: number, field: string): void {
  if (start < min || start > max) {
    throw new Error(`Range start ${start} is out of bounds [${min}, ${max}] in: ${field}`);
  }
  if (end < min || end > max) {
    throw new Error(`Range end ${end} is out of bounds [${min}, ${max}] in: ${field}`);
  }
}

export function parseCron(expression: string): CronResult {
  if (!expression || typeof expression !== "string") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = parts;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const fieldValues = [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr];

  const result = {} as CronResult;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    try {
      result[name] = parseField(fieldValues[i], min, max);
    } catch (err) {
      throw new Error(`Error parsing field "${name}" with value "${fieldValues[i]}": ${(err as Error).message}`);
    }
  }

  return result;
}

