        }
        if (start < min || end > max || start > end) {
          throw new Error(`Range out of bounds in expression: "${part}" (allowed ${min}-${max})`);
        }
        for (let i = start; i <= end; i += step) values.add(i);
      } else {
        const start = parseInt(rangePart, 10);
        if (isNaN(start)) {
          throw new Error(`Invalid start value in expression: "${part}"`);
        }
        if (start < min || start > max) {
          throw new Error(`Value out of bounds in expression: "${part}" (allowed ${min}-${max})`);
        }
        for (let i = start; i <= max; i += step) values.add(i);
      }
