  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${fieldName}"`);
    }
    assertInRange(start, range, fieldName);
    assertInRange(end, range, fieldName);
    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} in field "${fieldName}"`);
    }
    const values: number[] = [];
    for (let i = start; i <= end; i++) {
      values.push(i);
    }
    return values;
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${fieldName}"`);
  }
  assertInRange(num, range, fieldName);
  return [num];
}

function parseField(field: string, range: FieldRange, fieldName: string): number[] {
  const segments = field.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty segment in field "${fieldName}"`);
    }
    const values = parseSegment(trimmed, range, fieldName);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as Array<keyof CronResult>;

  return {
    minute: parseField(minuteField, FIELD_RANGES.minute, fieldNames[0]),
    hour: parseField(hourField, FIELD_RANGES.hour, fieldNames[1]),
    dayOfMonth: parseField(domField, FIELD_RANGES.dayOfMonth, fieldNames[2]),
    month: parseField(monthField, FIELD_RANGES.month, fieldNames[3]),
    dayOfWeek: parseField(dowField, FIELD_RANGES.dayOfWeek, fieldNames[4]),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: unknown };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  visited = new WeakSet<object>()
): FlatObject {
  if (obj === null || typeof obj !== "object") {
    return prefix ? { [prefix]: obj } : {};
  }

  if (visited.has(obj)) {
    return prefix ? { [prefix]: "[Circular]" } : {};
  }
  visited.add(obj);

  const result: FlatObject = {};

  const entries = Array.isArray(obj)
    ? obj.map((v, i) => [String(i), v] as const)
    : Object.entries(obj);

  if (entries.length === 0) {
    if (prefix) result[prefix] = obj;
    visited.delete(obj);
    return result;
  }

  for (const [key, value] of entries) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      Object.assign(result, flattenObject(value as NestedObject, newKey, visited));
    } else if (Array.isArray(value) && value.length > 0) {
      Object.assign(result, flattenObject(value as unknown as NestedObject, newKey, visited));
    } else {
      result[newKey] = value;
    }
  }

  visited.delete(obj);
  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    typeof value === "object" &&
    value !== null &&
    !Array.isArray(value) &&
    Object.getPrototypeOf(value) === Object.prototype
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronResult, FieldConfig> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function validateValue(value: number, config: FieldConfig, fieldName: string): number {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} out of range [${config.min}-${config.max}] for field "${fieldName}"`
    );
  }
  return value;
}

function parseWildcard(config: FieldConfig): number[] {
  return Array.from({ length: config.max - config.min + 1 }, (_, i) => config.min + i);
}

function parseStep(expr: string, config: FieldConfig, fieldName: string): number[] {
  const [rangeOrWild, stepStr] = expr.split("/");
  const step = parseInt(stepStr, 10);

  if (isNaN(step) || step <= 0) {
    throw new SyntaxError(`Invalid step value in expression "${expr}" for field "${fieldName}"`);
  }

  let start: number;
  let end: number;

  if (rangeOrWild === "*") {
    start = config.min;
    end = config.max;
  } else if (rangeOrWild.includes("-")) {
    const [s, e] = rangeOrWild.split("-").map((n) => parseInt(n, 10));
    start = validateValue(s, config, fieldName);
    end = validateValue(e, config, fieldName);
    if (start > end) {
      throw new RangeError(
        `Range start ${start} is greater than end ${end} for field "${fieldName}"`
      );
    }
  } else {
    start = validateValue(parseInt(rangeOrWild, 10), config, fieldName);
    end = config.max;
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseRange(expr: string, config: FieldConfig, fieldName: string): number[] {
  const [startStr, endStr] = expr.split("-");
  const start = validateValue(parseInt(startStr, 10), config, fieldName);
  const end = validateValue(parseInt(endStr, 10), config, fieldName);

  if (start > end) {
    throw new RangeError(
      `Range start ${start} is greater than end ${end} for field "${fieldName}"`
    );
  }

  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseField(expr: string, config: FieldConfig, fieldName: string): number[] {
  if (expr === "*") {
    return parseWildcard(config);
  }

  if (expr.includes(",")) {
    const parts = expr.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), config, fieldName)) {
        values.add(v);
      }
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  if (expr.includes("/")) {
    return parseStep(expr, config, fieldName);
  }

  if (expr.includes("-")) {
    return parseRange(expr, config, fieldName);
  }

  const num = parseInt(expr, 10);
  if (isNaN(num)) {
    throw new SyntaxError(`Invalid value "${expr}" for field "${fieldName}"`);
  }

  const validated = validateValue(num, config, fieldName);

  // Normalize dayOfWeek: treat 7 as 0 (Sunday)
  if (fieldName === "dayOfWeek" && validated === 7) {
    return [0];
  }

  return [validated];
}

export function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new SyntaxError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  const result: CronResult = {
    minute: parseField(minuteExpr, FIELD_CONFIGS.minute, "minute"),
    hour: parseField(hourExpr, FIELD_CONFIGS.hour, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, FIELD_CONFIGS.dayOfMonth, "dayOfMonth"),
    month: parseField(monthExpr, FIELD_CONFIGS.month, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, FIELD_CONFIGS.dayOfWeek, "dayOfWeek"),
  };

  // Deduplicate and sort dayOfWeek in case 7 was mapped to 0
  result.dayOfWeek = Array.from(new Set(result.dayOfWeek)).sort((a, b) => a - b);

  return result;
}

export default parseCron;

export type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

const FIELDS: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function parseField(expr: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Comma-separated list — recurse on each part
  if (expr.includes(",")) {
    const values = new Set<number>();
    for (const part of expr.split(",")) {
      for (const v of parseField(part.trim(), field)) {
        values.add(v);
      }
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  // Step value (e.g. "*/15" or "1-30/5" or "0/15")
  if (expr.includes("/")) {
    const slashIndex = expr.indexOf("/");
    const rangeExpr = expr.slice(0, slashIndex);
    const stepStr = expr.slice(slashIndex + 1);
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in "${field}" field: "${expr}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangeExpr === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangeExpr.includes("-")) {
      const dashIndex = rangeExpr.indexOf("-");
      rangeMin = parseInt(rangeExpr.slice(0, dashIndex), 10);
      rangeMax = parseInt(rangeExpr.slice(dashIndex + 1), 10);
      if (isNaN(rangeMin) || isNaN(rangeMax)) {
        throw new Error(`Invalid range in "${field}" field: "${expr}"`);
      }
    } else {
      rangeMin = parseInt(rangeExpr, 10);
      rangeMax = max;
      if (isNaN(rangeMin)) {
        throw new Error(`Invalid start value in "${field}" field: "${expr}"`);
      }
    }

    if (rangeMin < min || rangeMax > max || rangeMin > rangeMax) {
      throw new Error(
        `Range out of bounds in "${field}" field: "${expr}" (valid: ${min}–${max})`
      );
    }

    const values: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) {
      values.push(v);
    }
    return values;
  }

  // Wildcard — expand to full range
  if (expr === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Range (e.g. "1-5")
  if (expr.includes("-")) {
    const dashIndex = expr.indexOf("-");
    const start = parseInt(expr.slice(0, dashIndex), 10);
    const end = parseInt(expr.slice(dashIndex + 1), 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range in "${field}" field: "${expr}"`);
    }
    if (start > end) {
      throw new Error(`Range start exceeds end in "${field}" field: "${expr}"`);
    }
    if (start < min || end > max) {
      throw new Error(
        `Range out of bounds in "${field}" field: "${expr}" (valid: ${min}–${max})`
      );
    }

    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single number
  const num = parseInt(expr, 10);
  if (isNaN(num) || String(num) !== expr.trim()) {
    throw new Error(`Invalid value in "${field}" field: "${expr}"`);
  }
  if (num < min || num > max) {
    throw new Error(
      `Value ${num} out of range in "${field}" field (valid: ${min}–${max})`
    );
  }

  return [num];
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELDS.length; i++) {
    result[FIELDS[i]] = parseField(parts[i], FIELDS[i]);
  }

  return result;
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

function buildRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  // Step: */n  or  start/n  or  start-end/n
  if (segment.includes('/')) {
    const slashIdx = segment.indexOf('/');
    const rangePart = segment.slice(0, slashIdx);
    const stepStr  = segment.slice(slashIdx + 1);
    const step = parseInt(stepStr, 10);

    if (!Number.isInteger(step) || step <= 0) {
      throw new RangeError(`[${fieldName}] Invalid step "${stepStr}": must be a positive integer`);
    }

    let start: number;
    let end: number;

    if (rangePart === '*') {
      start = min;
      end   = max;
    } else if (rangePart.includes('-')) {
      const dashIdx = rangePart.indexOf('-');
      start = parseInt(rangePart.slice(0, dashIdx), 10);
      end   = parseInt(rangePart.slice(dashIdx + 1), 10);
    } else {
      start = parseInt(rangePart, 10);
      end   = max;
    }

    if (!Number.isInteger(start) || !Number.isInteger(end)) {
      throw new RangeError(`[${fieldName}] Invalid range in segment "${segment}"`);
    }
    if (start < min || end > max || start > end) {
      throw new RangeError(
        `[${fieldName}] Range ${start}-${end} out of bounds (valid: ${min}-${max})`
      );
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Wildcard
  if (segment === '*') {
    return buildRange(min, max);
  }

  // Range: n-m
  if (segment.includes('-')) {
    const dashIdx = segment.indexOf('-');
    const start = parseInt(segment.slice(0, dashIdx), 10);
    const end   = parseInt(segment.slice(dashIdx + 1), 10);

    if (!Number.isInteger(start) || !Number.isInteger(end)) {
      throw new RangeError(`[${fieldName}] Invalid range "${segment}"`);
    }
    if (start < min || end > max || start > end) {
      throw new RangeError(
        `[${fieldName}] Range ${start}-${end} out of bounds (valid: ${min}-${max})`
      );
    }
    return buildRange(start, end);
  }

  // Single value
  const value = parseInt(segment, 10);
  if (!Number.isInteger(value) || segment.trim() === '') {
    throw new TypeError(`[${fieldName}] Invalid value "${segment}"`);
  }
  if (value < min || value > max) {
    throw new RangeError(
      `[${fieldName}] Value ${value} out of bounds (valid: ${min}-${max})`
    );
  }
  return [value];
}

function parseField(field: string, min: number, max: number, fieldName: string): number[] {
  if (!field || typeof field !== 'string') {
    throw new TypeError(`[${fieldName}] Field must be a non-empty string`);
  }

  // Comma-separated list — each part is parsed independently
  const parts = field.split(',');
  const seen  = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === '') {
      throw new SyntaxError(`[${fieldName}] Empty segment in comma list "${field}"`);
    }
    for (const v of parseSegment(trimmed, min, max, fieldName)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== 'string' || expression.trim() === '') {
    throw new TypeError('parseCron: expression must be a non-empty string');
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `parseCron: expected 5 fields, got ${fields.length} in "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;
  const fieldNames: FieldName[] = ['minute', 'hour', 'dayOfMonth', 'month', 'dayOfWeek'];
  const raws = [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw];

  const parsed = fieldNames.map((name, i) =>
    parseField(raws[i], FIELD_RANGES[name].min, FIELD_RANGES[name].max, name)
  );

  return {
    minute:     parsed[0],
    hour:       parsed[1],
    dayOfMonth: parsed[2],
    month:      parsed[3],
    dayOfWeek:  parsed[4],
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function generateRange(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const part of field.split(",")) {
    if (part === "*") {
      generateRange(min, max).forEach((v) => values.add(v));
    } else if (part.startsWith("*/")) {
      const step = parseInt(part.slice(2), 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: ${part}`);
      }
      generateRange(min, max, step).forEach((v) => values.add(v));
    } else if (part.includes("/")) {
      const [rangePart, stepPart] = part.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: ${part}`);
      }
      if (rangePart === "*") {
        generateRange(min, max, step).forEach((v) => values.add(v));
      } else if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        const start = parseInt(startStr, 10);
        const end = parseInt(endStr, 10);
        if (isNaN(start) || isNaN(end)) {
          throw new Error(`Invalid range: ${rangePart}`);
        }
        if (start < min || end > max || start > end) {
          throw new Error(
            `Range ${rangePart} out of bounds [${min}, ${max}]`
          );
        }
        generateRange(start, end, step).forEach((v) => values.add(v));
      } else {
        const start = parseInt(rangePart, 10);
        if (isNaN(start) || start < min || start > max) {
          throw new Error(`Value ${rangePart} out of bounds [${min}, ${max}]`);
        }
        generateRange(start, max, step).forEach((v) => values.add(v));
      }
    } else if (part.includes("-")) {
      const [startStr, endStr] = part.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Invalid range: ${part}`);
      }
      if (start < min || end > max || start > end) {
        throw new Error(`Range ${part} out of bounds [${min}, ${max}]`);
      }
      generateRange(start, end).forEach((v) => values.add(v));
    } else {
      const num = parseInt(part, 10);
      if (isNaN(num)) {
        throw new Error(`Invalid value: ${part}`);
      }
      if (num < min || num > max) {
        throw new Error(`Value ${num} out of bounds [${min}, ${max}]`);
      }
      values.add(num);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const result = {} as CronFields;
  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(parts[i], min, max);
  }

  return result;
}

export default parseCron;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | unknown[];
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | unknown[];
    }
  }

  return result;
}

